import{bV as a,aL as t,u as s,G as i}from"./chunks/framework.D_inzUUb.js";const u=JSON.parse('{"title":"jsDelivr 缓存刷新方式","description":"","frontmatter":{"title":"jsDelivr 缓存刷新方式","date":"2025-07-23T00:00:00.000Z","categories":["技术文档","CDN","jsDelivr"],"tags":["jsDelivr","CDN","缓存刷新"]},"headers":[],"relativePath":"posts/202507/23-jsdelivr-cache-refresh.md","filePath":"posts/202507/23-jsdelivr-cache-refresh.md","lastUpdated":1777768110000}'),r={name:"posts/202507/23-jsdelivr-cache-refresh.md"};function l(o,e,d,n,h,c){return t(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="jsdelivr-缓存刷新方式" tabindex="-1">jsDelivr 缓存刷新方式 <a class="header-anchor" href="#jsdelivr-缓存刷新方式" aria-label="Permalink to &quot;jsDelivr 缓存刷新方式&quot;">​</a></h1><p>对于 <a href="https://cdn.jsdelivr.net/" target="_blank" rel="noreferrer">jsDelivr</a>，缓存刷新的方式也很简单，只需将想刷新的链接的开头的 <code>https://cdn.jsdelivr.net/</code> 替换成 <code>https://purge.jsdelivr.net/</code> 即可。</p><h2 id="使用示例" tabindex="-1">使用示例 <a class="header-anchor" href="#使用示例" aria-label="Permalink to &quot;使用示例&quot;">​</a></h2><h3 id="原始链接" tabindex="-1">原始链接 <a class="header-anchor" href="#原始链接" aria-label="Permalink to &quot;原始链接&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://cdn.jsdelivr.net/gh/aiastia/note@master/docs/public/blog/bg1.jpg</span></span></code></pre></div><h3 id="刷新缓存链接" tabindex="-1">刷新缓存链接 <a class="header-anchor" href="#刷新缓存链接" aria-label="Permalink to &quot;刷新缓存链接&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://purge.jsdelivr.net/gh/aiastia/note@master/docs/public/blog/bg1.jpg</span></span></code></pre></div><h2 id="工作原理" tabindex="-1">工作原理 <a class="header-anchor" href="#工作原理" aria-label="Permalink to &quot;工作原理&quot;">​</a></h2><p><code>purge.jsdelivr.net</code> 会触发 jsDelivr 重新从源服务器拉取文件，并清除之前的缓存。</p><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><ul><li>图片更新后立即看到新版本</li><li>CSS 文件修改后强制刷新</li><li>静态资源更新后立即生效</li></ul><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><ul><li><code>purge</code> 操作会消耗 jsDelivr API 配额</li><li>频繁刷新可能导致被限流</li><li>建议仅在更新后手动刷新</li></ul><hr><p><em>创建时间：2025-07-23</em></p>',15)])])}const v=a(r,[["render",l]]);export{u as __pageData,v as default};
